import { useEffect, useState, useCallback, useRef } from 'react';
import { invoke } from '@tauri-apps/api/core';
import { listen, type UnlistenFn } from '@tauri-apps/api/event';
import {
  Button,
  Card,
  CardBody,
  CardTitle,
  TextInput,
  Label,
  Flex,
  FlexItem,
} from '@patternfly/react-core';
import { PlayIcon, StopIcon, TerminalIcon } from '@patternfly/react-icons';

interface ProcessInfo {
  id: string;
  cmd: string;
  cwd: string;
  rows: number;
  cols: number;
  running: boolean;
}

interface PtyOutput {
  id: string;
  data: string;
}

interface PtyExit {
  id: string;
  code: number | null;
}

interface TerminalPanelProps {
  height?: number;
  defaultCwd?: string;
}

export function TerminalPanel({ height = 300, defaultCwd }: TerminalPanelProps) {
  const [processInfo, setProcessInfo] = useState<ProcessInfo | null>(null);
  const [output, setOutput] = useState<string[]>([]);
  const [input, setInput] = useState('');
  const [status, setStatus] = useState<'idle' | 'running' | 'stopped'>('idle');
  const outputRef = useRef<HTMLDivElement>(null);
  const unlistenRef = useRef<UnlistenFn[]>([]);

  // Auto-scroll to bottom when output changes
  useEffect(() => {
    if (outputRef.current) {
      outputRef.current.scrollTop = outputRef.current.scrollHeight;
    }
  }, [output]);

  // Setup event listeners
  useEffect(() => {
    const setupListeners = async () => {
      const unlistenOutput = await listen<PtyOutput>('pty-output', (event) => {
        if (processInfo && event.payload.id === processInfo.id) {
          setOutput((prev) => [...prev, event.payload.data]);
        }
      });

      const unlistenExit = await listen<PtyExit>('pty-exit', (event) => {
        if (processInfo && event.payload.id === processInfo.id) {
          setStatus('stopped');
          setOutput((prev) => [
            ...prev,
            `\n\x1b[33m[Process exited with code: ${event.payload.code ?? 'unknown'}]\x1b[0m\n`,
          ]);
        }
      });

      unlistenRef.current = [unlistenOutput, unlistenExit];
    };

    if (processInfo) {
      setupListeners();
    }

    return () => {
      unlistenRef.current.forEach((unlisten) => unlisten());
      unlistenRef.current = [];
    };
  }, [processInfo]);

  // Spawn a new shell process
  const handleSpawn = useCallback(async () => {
    try {
      // Detect shell based on platform
      const shell = navigator.userAgent.includes('Mac') ? '/bin/zsh' : '/bin/bash';
      const cwd = defaultCwd || process.env.HOME || '/';

      const info = await invoke<ProcessInfo>('pty_spawn', {
        cmd: shell,
        args: [],
        cwd,
        rows: 24,
        cols: 80,
      });

      setProcessInfo(info);
      setOutput([`\x1b[32m[Shell started: ${info.cmd}]\x1b[0m\n`]);
      setStatus('running');
    } catch (error) {
      setOutput((prev) => [...prev, `\x1b[31m[Error: ${error}]\x1b[0m\n`]);
    }
  }, [defaultCwd]);

  // Kill the current process
  const handleKill = useCallback(async () => {
    if (!processInfo) return;

    try {
      await invoke('pty_kill', { id: processInfo.id });
      setStatus('stopped');
    } catch (error) {
      setOutput((prev) => [...prev, `\x1b[31m[Kill error: ${error}]\x1b[0m\n`]);
    }
  }, [processInfo]);

  // Send command to the process
  const handleSend = useCallback(async () => {
    if (!processInfo || !input.trim()) return;

    try {
      // Send with newline to execute command
      await invoke('pty_write', { id: processInfo.id, data: input + '\n' });
      setInput('');
    } catch (error) {
      setOutput((prev) => [...prev, `\x1b[31m[Write error: ${error}]\x1b[0m\n`]);
    }
  }, [processInfo, input]);

  // Handle Enter key in input
  const handleKeyDown = useCallback(
    (event: React.KeyboardEvent) => {
      if (event.key === 'Enter') {
        handleSend();
      }
    },
    [handleSend]
  );

  // Parse ANSI codes for display (simple version - strips codes for now)
  const parseAnsi = (text: string): string => {
    // Keep ANSI codes for now - we'll use CSS for proper display
    return text;
  };

  return (
    <Card>
      <CardTitle>
        <Flex>
          <FlexItem>
            <TerminalIcon /> Terminal (PTY Test)
          </FlexItem>
          <FlexItem>
            <Label color={status === 'running' ? 'green' : status === 'stopped' ? 'red' : 'grey'}>
              {status}
            </Label>
          </FlexItem>
        </Flex>
      </CardTitle>
      <CardBody>
        {/* Output area */}
        <div
          ref={outputRef}
          style={{
            height: `${height}px`,
            backgroundColor: '#1e1e1e',
            color: '#d4d4d4',
            fontFamily: 'monospace',
            fontSize: '13px',
            padding: '8px',
            overflowY: 'auto',
            whiteSpace: 'pre-wrap',
            borderRadius: '4px',
            marginBottom: '8px',
          }}
        >
          {output.map((line, i) => (
            <span key={i}>{parseAnsi(line)}</span>
          ))}
          {output.length === 0 && (
            <span style={{ color: '#888' }}>
              Click "Start Shell" to spawn a PTY process...
            </span>
          )}
        </div>

        {/* Controls */}
        <Flex>
          {status !== 'running' ? (
            <FlexItem>
              <Button variant="primary" onClick={handleSpawn} icon={<PlayIcon />}>
                Start Shell
              </Button>
            </FlexItem>
          ) : (
            <>
              <FlexItem grow={{ default: 'grow' }}>
                <TextInput
                  value={input}
                  onChange={(_e, val) => setInput(val)}
                  onKeyDown={handleKeyDown}
                  placeholder="Type command and press Enter..."
                  aria-label="Command input"
                />
              </FlexItem>
              <FlexItem>
                <Button variant="secondary" onClick={handleSend}>
                  Send
                </Button>
              </FlexItem>
              <FlexItem>
                <Button variant="danger" onClick={handleKill} icon={<StopIcon />}>
                  Kill
                </Button>
              </FlexItem>
            </>
          )}
        </Flex>

        {/* Process info */}
        {processInfo && (
          <div style={{ marginTop: '8px', fontSize: '12px', color: '#888' }}>
            <strong>Process ID:</strong> {processInfo.id} |{' '}
            <strong>Size:</strong> {processInfo.cols}x{processInfo.rows} |{' '}
            <strong>CWD:</strong> {processInfo.cwd}
          </div>
        )}
      </CardBody>
    </Card>
  );
}

