import { useState, useCallback } from 'react';
import {
  Button,
  Card,
  CardBody,
  CardTitle,
  Content,
  Label,
  Masthead,
  MastheadBrand,
  MastheadMain,
  Page,
  PageSection,
  Title,
  Alert,
  AlertActionCloseButton,
} from '@patternfly/react-core';
import { TabBar, KanbanBoard, LogPanel } from './components';
import type { LogEntry } from './components';
import type { Project, Feature } from './state/store';

// Mock projects for demonstration
const createMockProject = (id: string, name: string): Project => ({
  id,
  path: `/Users/example/${name.toLowerCase().replace(/\s+/g, '-')}`,
  name,
  harness: {
    progressFile: '.harness/progress.txt',
    featuresFile: '.harness/features.json',
  },
});

// Mock processes for log panel
const MOCK_PROCESSES = [
  { id: 'dev-server', name: 'Dev Server' },
  { id: 'tauri', name: 'Tauri' },
  { id: 'typescript', name: 'TypeScript' },
];

// Mock log entries with ANSI colors
const createMockLogs = (): LogEntry[] => {
  const now = Date.now();
  return [
    {
      timestamp: now - 5000,
      processId: 'dev-server',
      processName: 'Dev Server',
      message: '\x1b[32m✓\x1b[0m Server started at \x1b[36mhttp://localhost:5173\x1b[0m',
      level: 'info',
    },
    {
      timestamp: now - 4500,
      processId: 'tauri',
      processName: 'Tauri',
      message: '\x1b[34mINFO\x1b[0m Compiling hq-app v0.1.0',
      level: 'info',
    },
    {
      timestamp: now - 4000,
      processId: 'typescript',
      processName: 'TypeScript',
      message: '\x1b[33mwarning\x1b[0m: Unused variable \'foo\' in src/App.tsx:42',
      level: 'warn',
    },
    {
      timestamp: now - 3500,
      processId: 'dev-server',
      processName: 'Dev Server',
      message: 'HMR update: \x1b[1msrc/components/LogPanel.tsx\x1b[0m',
      level: 'info',
    },
    {
      timestamp: now - 3000,
      processId: 'tauri',
      processName: 'Tauri',
      message: '\x1b[32mFinished\x1b[0m dev [unoptimized + debuginfo] target(s) in 2.34s',
      level: 'info',
    },
    {
      timestamp: now - 2500,
      processId: 'tauri',
      processName: 'Tauri',
      message: '\x1b[34mINFO\x1b[0m Running webview at \x1b[36mhttp://localhost:1420\x1b[0m',
      level: 'info',
    },
    {
      timestamp: now - 2000,
      processId: 'typescript',
      processName: 'TypeScript',
      message: '\x1b[91merror\x1b[0m TS2339: Property \'test\' does not exist on type \'never\'',
      level: 'error',
    },
    {
      timestamp: now - 1500,
      processId: 'dev-server',
      processName: 'Dev Server',
      message: '[vite] page reload src/main.tsx',
      level: 'debug',
    },
    {
      timestamp: now - 1000,
      processId: 'tauri',
      processName: 'Tauri',
      message: '\x1b[90mDEBUG\x1b[0m Window created with ID: main',
      level: 'debug',
    },
    {
      timestamp: now - 500,
      processId: 'dev-server',
      processName: 'Dev Server',
      message: '\x1b[32m✓\x1b[0m Build completed in \x1b[1m234ms\x1b[0m',
      level: 'info',
    },
  ];
};

// Mock features data (matches HQ .harness/features.json)
const MOCK_FEATURES: Feature[] = [
  {
    id: 'F001',
    description: 'Multi-project tab management - Open and manage multiple projects via tabs',
    category: 'ui',
    priority: 'high',
    status: 'done',
    passes: true,
    steps: [
      'Create TabBar component with PatternFly Tabs',
      'Implement tab state in @zazcart/tools state-machine',
      'Add new tab (+) and close tab (X) functionality',
      'Support tab reordering via drag-and-drop',
      'Display project name from package.json or folder name',
    ],
  },
  {
    id: 'F002',
    description: 'Kanban board view - Visual feature tracking with BACKLOG|TODO|DOING|REVIEW|QA|DONE columns',
    category: 'ui',
    priority: 'high',
    status: 'doing',
    passes: false,
    steps: [
      'Create KanbanBoard component with 6 columns',
      'Create KanbanCard component for feature display',
      'Read features from .harness/features.json',
      'Map feature status to appropriate column',
      'Support card expansion for details',
    ],
  },
  {
    id: 'F003',
    description: 'Real-time log panel - Live output from running processes with ANSI color support',
    category: 'ui',
    priority: 'high',
    status: 'backlog',
    passes: false,
    steps: [
      'Create LogPanel component with virtual scroll',
      'Implement ANSI color parsing',
      'Add process filter dropdown',
      'Implement search within logs',
      'Add auto-scroll toggle and clear button',
    ],
  },
  {
    id: 'F004',
    description: 'PTY process controller - Spawn and control shell processes via Rust backend',
    category: 'core',
    priority: 'critical',
    status: 'backlog',
    passes: false,
    steps: [
      'Add portable-pty crate to Cargo.toml',
      'Implement pty_spawn Tauri command',
      'Implement pty_write for sending keystrokes',
      'Implement pty_resize for terminal resize',
      'Implement pty_kill for process termination',
      'Stream PTY output via Tauri events',
    ],
  },
  {
    id: 'F009',
    description: 'State management setup - Configure @zazcart/tools state machine',
    category: 'core',
    priority: 'critical',
    status: 'done',
    passes: true,
    steps: [
      'Create store.ts with createMachine and createSlice',
      'Define types: Project, Feature, Process, LogEntry',
      'Create slices: ui, projects, features, processes, logs',
      'Implement selectors for derived state',
      'Connect to React components',
    ],
  },
  {
    id: 'F010',
    description: 'Tauri project initialization - Setup Tauri 2.x with React 19',
    category: 'setup',
    priority: 'critical',
    status: 'done',
    passes: true,
    steps: [
      'Run bun create tauri-app with react-ts template',
      'Add React 19 and PatternFly 6 dependencies',
      'Add @zazcart/tools dependency',
      'Configure vite.config.ts',
      'Verify app runs with bun tauri dev',
    ],
  },
];

function App() {
  // Tab state management
  const [projects, setProjects] = useState<Project[]>([
    createMockProject('proj-1', 'HQ Dashboard'),
  ]);
  const [activeProjectId, setActiveProjectId] = useState('proj-1');
  const [showWelcome, setShowWelcome] = useState(true);

  // Theme state
  const [theme, setTheme] = useState<'light' | 'dark' | 'system'>('system');
  const stats = { completed: 4, total: 10 }; // F001 + F002 + F009 + F010

  // Log state
  const [logs, setLogs] = useState<LogEntry[]>(createMockLogs);

  const handleClearLogs = useCallback(() => {
    setLogs([]);
  }, []);

  // Tab handlers
  const handleSelectProject = useCallback((projectId: string) => {
    setActiveProjectId(projectId);
  }, []);

  const handleCloseProject = useCallback((projectId: string) => {
    setProjects((prev) => {
      const filtered = prev.filter((p) => p.id !== projectId);
      // If closing active tab, switch to previous or next
      if (activeProjectId === projectId && filtered.length > 0) {
        const idx = prev.findIndex((p) => p.id === projectId);
        const newActive = filtered[Math.max(0, idx - 1)];
        setActiveProjectId(newActive.id);
      }
      return filtered;
    });
  }, [activeProjectId]);

  const handleAddProject = useCallback(() => {
    const id = `proj-${Date.now()}`;
    const newProject = createMockProject(id, `Project ${projects.length + 1}`);
    setProjects((prev) => [...prev, newProject]);
    setActiveProjectId(id);
  }, [projects.length]);

  const handleReorderProjects = useCallback((order: string[]) => {
    setProjects((prev) => {
      const projectMap = new Map(prev.map((p) => [p.id, p]));
      return order.map((id) => projectMap.get(id)).filter(Boolean) as Project[];
    });
  }, []);

  // Get active project
  const activeProject = projects.find((p) => p.id === activeProjectId);

  const masthead = (
    <Masthead>
      <MastheadMain>
        <MastheadBrand>
          <Title headingLevel="h1" size="xl">HQ</Title>
        </MastheadBrand>
        <Label color="blue" isCompact>Harness Orchestrator</Label>
      </MastheadMain>
    </Masthead>
  );

  return (
    <Page masthead={masthead}>
      {/* Tab Bar */}
      <TabBar
        projects={projects}
        activeProjectId={activeProjectId}
        onSelect={handleSelectProject}
        onClose={handleCloseProject}
        onAdd={handleAddProject}
        onReorder={handleReorderProjects}
      />

      {/* Welcome Alert */}
      {showWelcome && (
        <PageSection padding={{ default: 'padding' }}>
          <Alert
            variant="info"
            title="Welcome to HQ - Harness Orchestrator"
            actionClose={<AlertActionCloseButton onClose={() => setShowWelcome(false)} />}
          >
            <Content component="p">
              Manage your AI agent development sessions with visual task boards and real-time logs.
            </Content>
          </Alert>
        </PageSection>
      )}

      {/* Project Content */}
      <PageSection>
        <Card>
          <CardTitle>
            {activeProject ? activeProject.name : 'No Project Selected'}
          </CardTitle>
          <CardBody>
            {activeProject ? (
              <>
                <Content component="p">
                  <strong>Path:</strong> {activeProject.path}
                </Content>
                <Content component="p">
                  <strong>Harness:</strong> {activeProject.harness.featuresFile}
                </Content>
                <Content component="p">
                  <strong>Theme:</strong> {theme}
                </Content>
                <Content component="p">
                  <strong>Features:</strong> {stats.completed}/{stats.total} complete
                </Content>
                <div style={{ marginTop: '16px', display: 'flex', gap: '8px' }}>
                  <Button
                    variant="primary"
                    onClick={() => setTheme(theme === 'dark' ? 'light' : 'dark')}
                  >
                    Toggle Theme
                  </Button>
                  <Button variant="secondary" onClick={handleAddProject}>
                    Open Another Project
                  </Button>
                </div>
              </>
            ) : (
              <Content component="p">
                Click "Open a project to get started" to begin.
              </Content>
            )}
          </CardBody>
        </Card>
      </PageSection>

      {/* Kanban Board */}
      <PageSection>
        <Card>
          <CardTitle>Feature Board</CardTitle>
          <CardBody>
            <KanbanBoard features={MOCK_FEATURES} />
          </CardBody>
        </Card>
      </PageSection>

      {/* Log Panel */}
      <PageSection>
        <Card>
          <CardTitle>Process Logs</CardTitle>
          <CardBody>
            <LogPanel
              logs={logs}
              processes={MOCK_PROCESSES}
              onClear={handleClearLogs}
              height={300}
            />
          </CardBody>
        </Card>
      </PageSection>
    </Page>
  );
}

export default App;

